class Solution {
    public int minLength(String s) {
        int n = s.length();
        int[] dp = new int[n + 1];
        Arrays.fill(dp, Integer.MAX_VALUE);
        dp[0] = 0;
        for (int i = 1; i <= n; i++) {
            if (s.charAt(i - 1) == 'A' && i >= 2 && s.charAt(i - 2) == 'B') {
                dp[i] = Math.min(dp[i], dp[i - 2]);
            }
            if (s.charAt(i - 1) == 'C' && i >= 2 && s.charAt(i - 2) == 'D') {
                dp[i] = Math.min(dp[i], dp[i - 2]);
            } else {
                dp[i] = Math.min(dp[i - 1], dp[i]);
            }
        }
        return dp[n];
    }
}
